1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_BLOCK_SIZE = 3;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	};
26	
27	const COMPONENT_INSURANCE_VALUE = 250;
28	const DEDUCTIBLE = 100;
29	const CAP_MULTIPLIER = 2;
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
34	
35	const isKnownItemType = (item: any): boolean =>
36	  item.type in MAIN_ITEM_PREMIUMS || COMPONENT_TYPES.has(item.type);
37	
38	const componentGroupPremium = (count: number): number =>
39	  count === COMPONENT_BLOCK_SIZE
40	    ? COMPONENT_BLOCK_PREMIUM
41	    : count * COMPONENT_PREMIUM;
42	
43	const calculateMainItemBaseTotal = (mainItems: any[]): number =>
44	  mainItems.reduce(
45	    (sum, item) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0),
46	    0,
47	  );
48	
49	const calculateComponentTotal = (components: any[]): number => {
50	  const componentCounts: Record<string, number> = {};
51	  for (const item of components) {
52	    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
53	  }
54	  return Object.values(componentCounts).reduce(
55	    (sum, count) => sum + componentGroupPremium(count),
56	    0,
57	  );
58	};
59	
60	const calculateItemLevelSurcharges = (mainItems: any[]): number =>
61	  mainItems.reduce((sum, item) => {
62	    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
63	    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
64	    const enchantmentSurcharge = item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
65	    return sum + cursedSurcharge + enchantmentSurcharge;
66	  }, 0);
67	
68	const validateItems = (items: any[]): void => {
69	  for (const item of items) {
70	    if (!isKnownItemType(item)) {
71	      throw new Error(`Unknown item type: ${item.type}`);
72	    }
73	  }
74	};
75	
76	const calculateInsuranceSum = (items: any[]): number =>
77	  items.reduce(
78	    (sum: number, item: any) =>
79	      sum + (isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUES[item.type] ?? 0)),
80	    0,
81	  );
82	
83	const calculatePremium = (items: any[], customer: any, quoteCount: number): number => {
84	  const mainItems = items.filter((item: any) => !isComponent(item));
85	  const components = items.filter(isComponent);
86	  const basePremiumSum = calculateMainItemBaseTotal(mainItems) + calculateComponentTotal(components);
87	  const itemSurcharges = calculateItemLevelSurcharges(mainItems);
88	  const firstInsurance = basePremiumSum * FIRST_INSURANCE_RATE;
89	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremiumSum * LOYALTY_DISCOUNT_RATE : 0;
90	  const followUpDiscount = quoteCount > 0 ? basePremiumSum * FOLLOW_UP_DISCOUNT_RATE : 0;
91	  return Math.ceil(basePremiumSum + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
92	};
93	
94	const CLAIM_ENCHANTMENT_THRESHOLD = 8;
95	const CLAIM_ENCHANTMENT_RATE = 0.5;
96	
97	const calculateClaimPayout = (damages: any[], policyItems: any[]): number =>
98	  damages.reduce((total: number, damage: any) => {
99	    const item = policyItems.find((i: any) => i.type === damage.itemType);
100	    let reimbursement = damage.amount;
101	    if (item && item.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD) {
102	      reimbursement = damage.amount * CLAIM_ENCHANTMENT_RATE;
103	    }
104	    return total + Math.max(0, reimbursement - DEDUCTIBLE);
105	  }, 0);
106	
107	export const processScenario = (scenario: any): any => {
108	  const results: any[] = [];
109	  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
110	  let quoteCount = 0;
111	  for (let i = 0; i < scenario.steps.length; i++) {
112	    const step = scenario.steps[i];
113	    if (step.op === "quote") {
114	      validateItems(step.items);
115	      const premium = calculatePremium(step.items, scenario.customer, quoteCount);
116	      const insuranceSum = calculateInsuranceSum(step.items);
117	      policies[i] = { items: step.items, remainingCap: insuranceSum * CAP_MULTIPLIER };
118	      results.push({ premium });
119	      quoteCount++;
120	    } else if (step.op === "claim") {
121	      const policy = policies[step.policy];
122	      const totalPayout = calculateClaimPayout(step.incident.damages, policy.items);
123	      policy.remainingCap -= totalPayout;
124	      results.push({ payout: totalPayout, remainingCap: policy.remainingCap });
125	    }
126	  }
127	  return { results };
128	};
